async (params, browser) => {
  // Open Airtable table
  await browser.open(`${params.table_url}`)

  // Wait for table to load
  await browser.waitForSelector('.dataRow, [data-rowindex], .headerRow, .viewSidebar, [data-testid="view-sidebar"]', 15000)

  // Let table fully render
  await browser.wait(2000)

  // Open views sidebar
  const open_sidebar = await browser.evaluate(`const sidebar = document.querySelector('.viewSidebar, [data-testid="view-sidebar"], .viewMenuPanel'); if (!sidebar) { const viewsBtn = document.querySelector('[data-testid="view-sidebar-toggle"], [aria-label="Views"], .viewMenuToggle, button[aria-label*="view" i]'); if (viewsBtn) { viewsBtn.click(); await new Promise(r => setTimeout(r, 1500)); } } return { sidebar_opened: true }`)

  // Wait for sidebar to render
  await browser.wait(1500)

  // Extract view names and types
  const result = await browser.evaluate(`const views = []; const viewItems = document.querySelectorAll('.viewSidebar [data-testid="view-item"], [data-testid="view-sidebar"] [role="treeitem"], .viewMenuPanel .viewItem, .viewSidebar .viewListItem, [class*="ViewListItem"], [class*="viewMenuItem"]'); if (viewItems.length > 0) { viewItems.forEach(item => { const nameEl = item.querySelector('[data-testid="view-name"], .viewName, span, a'); const name = nameEl?.textContent?.trim() || item.textContent?.trim() || ''; const iconEl = item.querySelector('svg, [data-testid="view-type-icon"], .viewTypeIcon'); const typeAttr = item.getAttribute('data-view-type') || iconEl?.getAttribute('aria-label') || ''; let viewType = typeAttr || 'unknown'; if (!typeAttr) { const text = (item.className + ' ' + (iconEl?.outerHTML || '')).toLowerCase(); if (text.includes('grid')) viewType = 'grid'; else if (text.includes('kanban') || text.includes('board')) viewType = 'kanban'; else if (text.includes('calendar')) viewType = 'calendar'; else if (text.includes('gallery')) viewType = 'gallery'; else if (text.includes('form')) viewType = 'form'; else if (text.includes('gantt') || text.includes('timeline')) viewType = 'timeline'; else if (text.includes('list')) viewType = 'list'; } const link = item.querySelector('a'); const url = link?.href || ''; const isActive = item.classList.contains('active') || item.getAttribute('aria-selected') === 'true'; if (name && name.length > 0) { views.push({ name: name.substring(0, 100), type: viewType, url: url, is_active: isActive }); } }); } else { const viewTabs = document.querySelectorAll('.viewTab, [role="tab"], .viewTabBar button, .viewBar a'); viewTabs.forEach(tab => { const name = tab.textContent?.trim() || ''; const isActive = tab.classList.contains('active') || tab.getAttribute('aria-selected') === 'true'; if (name && name.length > 0) { views.push({ name: name.substring(0, 100), type: 'unknown', url: tab.href || '', is_active: isActive }); } }); } return { result_count: views.length, views: views }`)

  return result
}
